defmodule MyApp.Catalog.Product do
  use Ecto.Schema
  import Ecto.Changeset

  schema "products" do
    field :name, :string
    field :description, :string
    field :price, :decimal
    field :category, :string
    field :sku, :string
    field :active, :boolean, default: true
    field :stock_quantity, :integer, default: 0

    timestamps()
  end

  @required_fields ~w(name price sku)a
  @optional_fields ~w(description category active stock_quantity)a

  def changeset(product, attrs) do
    product
    |> cast(attrs, @required_fields ++ @optional_fields)
    |> validate_required(@required_fields)
    |> validate_length(:name, min: 1, max: 255)
    |> validate_number(:price, greater_than_or_equal_to: 0)
    |> validate_number(:stock_quantity, greater_than_or_equal_to: 0)
    |> unique_constraint(:sku)
  end
end

defmodule MyAppWeb.ProductJSON do
  alias MyApp.Catalog.Product

  def index(%{products: products}) do
    %{data: for(product <- products, do: data(product))}
  end

  def show(%{product: product}) do
    %{data: data(product)}
  end

  defp data(%Product{} = product) do
    %{
      id: product.id,
      name: product.name,
      description: product.description,
      price: product.price,
      category: product.category,
      sku: product.sku,
      active: product.active,
      stock_quantity: product.stock_quantity,
      inserted_at: product.inserted_at,
      updated_at: product.updated_at
    }
  end
end